-- =====================================================
-- Migration 002: Set Module 7 as Preview Module
-- Run this in Supabase SQL Editor to update the LIVE database
-- =====================================================

-- Step 1: Remove preview flag from Module 1 (was the old demo module)
UPDATE modules SET is_preview = false WHERE module_number = '1';
UPDATE lessons SET is_preview = false
WHERE module_id = (SELECT id FROM modules WHERE module_number = '1');

-- Step 2: Set Module 7 as the preview module
UPDATE modules SET is_preview = true WHERE module_number = '7';

-- Step 3: Set all Module 7 lessons as preview (accessible to all authenticated users)
UPDATE lessons SET is_preview = true
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7');

-- Step 4: Update Module 7 lesson titles to match real curriculum
UPDATE lessons SET title = 'Identifying Core Wounds'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 1;

UPDATE lessons SET title = 'The Power of Forgiveness'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 2;

UPDATE lessons SET title = 'From Letting Go to Living Free'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 3;

-- Step 5: Enrich Module 7, Lesson 1 content
UPDATE lessons SET content_json = '{"estimated_minutes":12,"blocks":[{"type":"heading","content":"Identifying Core Wounds"},{"type":"text","content":"Discover the deep wounds that silently control your reactions. In this lesson, you will learn to recognize the patterns that have been running beneath the surface of your relationships — patterns rooted in early attachment experiences and childhood pain."},{"type":"callout","icon":"heart","content":"Core wounds are not character flaws. They are survival strategies your younger self created to stay safe. Recognizing them is the first act of healing."},{"type":"text","content":"Every couple faces moments where a small disagreement suddenly feels enormous. That is often a sign that a core wound has been touched — a deep belief about your worth, safety, or lovability that was formed long before your current relationship."}]}'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 1;

-- Step 6: Enrich Module 7, Lesson 2 content
UPDATE lessons SET content_json = '{"estimated_minutes":15,"blocks":[{"type":"heading","content":"The Power of Forgiveness"},{"type":"text","content":"Forgiveness is not about excusing what happened. It is about releasing the weight so you can move forward. In this lesson, you will explore what real forgiveness looks like — and what it does not."},{"type":"callout","icon":"lightbulb","content":"Forgiveness does not mean reconciliation. It does not mean forgetting. It means choosing to stop letting the pain control your present."},{"type":"text","content":"When we carry resentment, our nervous system stays in a state of low-grade threat. Forgiveness — done at your own pace, on your own terms — helps your body finally exhale."}]}'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 2;

-- Step 7: Enrich Module 7, Lesson 3 (From Letting Go to Living Free) — FULL CONTENT
UPDATE lessons SET content_json = '{"estimated_minutes":25,"blocks":[{"type":"heading","content":"From Letting Go to Living Free"},{"type":"subheading","content":"Exceptional Mastery & Belief Reprogramming"},{"type":"bold_text","content":"Understanding the BTEA Cycle: Beliefs → Thoughts → Emotions → Actions"},{"type":"text","content":"This invisible loop powers most of what we do. We rarely see it running — we just feel the emotion and react. Once you understand it, you get to step in and take the wheel."},{"type":"list","items":["You carry core beliefs (many formed before age 7, shaped by your early attachment style: secure, anxious, avoidant, or disorganized).","Those beliefs spark automatic thoughts, often slipping in without you noticing.","Thoughts trigger real neurochemical emotions.","Your Reticular Activating System (RAS) acts as the brain''s loyal filter, quietly scanning for evidence that matches those core beliefs.","Emotions fuel your actions — even the ones you wish you could take back."]},{"type":"divider"},{"type":"subheading","content":"The 4 Attachment Styles"},{"type":"text","content":"We have talked about these in a previous module, but here is a quick overview with real-life examples in adult relationships:"},{"type":"callout","icon":"lightbulb","content":"Secure Attachment (the oak tree — strong roots, flexible branches): Comfortable with intimacy and independence. Trusts others, communicates openly, handles conflict calmly, and believes they are worthy of love."},{"type":"callout","icon":"heart","content":"Anxious Attachment (the octopus — reaching for reassurance): Craves closeness but fears abandonment. Seeks constant validation, gets jealous or clingy during uncertainty."},{"type":"callout","icon":"alert","content":"Avoidant Attachment (the turtle in its shell): Prioritizes independence, pulls back from vulnerability. Values self-reliance and avoids deep emotions."},{"type":"callout","icon":"alert","content":"Disorganized Attachment (the cat in a tree — wants down, but is terrified): Craves connection but fears it. Swings between pursuing intensely and withdrawing suddenly."},{"type":"text","content":"These styles are not fixed labels — they are early patterns that can shift toward secure and safe relationships with consistent practice (like the tools we are using here). Most people lean toward one, but show traits of others in different situations."},{"type":"divider"},{"type":"subheading","content":"Neurochemical Emotions"},{"type":"text","content":"When we say emotions are neurochemical reactions, we mean they are not just feelings in your head — they are physical events in your body and brain. Every emotion triggers a cascade of chemicals:"},{"type":"list","items":["Fear or anxiety floods you with adrenaline and cortisol (fight/flight).","Sadness or grief lowers serotonin and dopamine while increasing stress hormones.","Joy or connection releases oxytocin, endorphins, and dopamine — the feel-good chemicals that make you feel safe and bonded."]},{"type":"text","content":"These chemicals change your heart rate, breathing, muscle tension, even digestion. That is why a triggered belief can make your chest tighten, your stomach drop, or your whole body freeze."},{"type":"callout","icon":"heart","content":"Reprogramming can shift those chemical responses so calm, safety, and peace become the new default."},{"type":"divider"},{"type":"subheading","content":"The Reticular Activating System (RAS)"},{"type":"text","content":"The RAS functions like a filter in the brain. It helps determine what you notice, what stands out, and what your mind automatically pays attention to. When you have carried limiting beliefs for a long time, your RAS has been quietly scanning for evidence that confirms those beliefs."},{"type":"text","content":"Here is the hopeful part. The RAS is not fixed. As you begin gently updating your beliefs, your brain also begins learning to look for different kinds of evidence. You start to notice moments of safety. You see small efforts, subtle repairs, and tiny signs of growth."},{"type":"divider"},{"type":"subheading","content":"Why Negative Emotions Are Actually Your Best Friends"},{"type":"text","content":"Emotions are never the enemy. They are messengers. They are the smoke alarm telling you a belief is triggered or a need is unmet. Here is the order that sets you free:"},{"type":"list","ordered":true,"items":["Feel the emotion (do not shame it). Pause and allow it to be there fully. Name it, breathe into it, and notice where it lives in your body.","Question the thought or belief behind it. Ask gently: Is this 100% true? What evidence supports or challenges this story?","Identify the unmet need. Ask: What do I really need right now — reassurance, rest, connection, boundaries, or self-kindness?"]},{"type":"quote","content":"Your feelings reveal your internal programming far more than they describe what is actually happening outside.","attribution":"Trisha Jamison"},{"type":"divider"},{"type":"subheading","content":"Your Brain Is a Needs-Meeting Machine"},{"type":"text","content":"Your brain is a brilliant needs-meeting machine. The problem is, it will always choose the fastest path to feel safe and secure — not necessarily the wisest or healthiest one — until you give it better, more effective options."},{"type":"divider"},{"type":"subheading","content":"Reprogramming Your Brain: The First Steps"},{"type":"text","content":"There are many steps to truly reprogramming your brain and nervous system so the old survival code can finally rest. Right now, we are focusing on the foundational first two exercises. These are powerful on their own, and they build the safety and awareness your system needs."},{"type":"exercise","title":"Exercise 1: What Beliefs Shape My Life?","prompt":"Bring conscious awareness to the limiting beliefs quietly running each area of your life, so you can plant new, intentional seeds of what is possible. For each area of your life, write one clear, hopeful sentence describing the outcome you truly desire — as if anything were possible and success were guaranteed.","steps":["Ask yourself: What would I want to create if I knew I was safe, supported, and loved, no matter what?","Keep your statements simple and positive, using present or near-future tense.","If you get stuck, start with: I am free to…"]},{"type":"exercise","title":"Exercise 2: The Emotional Processing Tool","prompt":"Interrupt emotional spirals in real time by slowing down, identifying what you are feeling, uncovering the story underneath it, and choosing a healthier response. Practice this on one or two real moments per week.","steps":["Name the Emotion: What am I feeling right now? (Angry, Anxious, Overwhelmed, Hurt, Sad, Lonely, Ashamed, Insecure, Powerless, Unseen, Unsafe)","Identify the Trigger: What just happened? Be specific — describe the moment, not the entire history.","Uncover the Meaning: What did I make this mean about me, my worth, my relationships, or my future?","Question the Story: Can I know with 100% certainty this belief is true?","Challenge & Update: List three pieces of evidence that do NOT support the painful belief. Find a kinder, more balanced explanation.","Name the Need: What do I actually need right now — reassurance, rest, connection, boundaries, validation, space, or self-compassion?","Choose a Healthy Strategy: What is one small, realistic way I can meet this need?"]},{"type":"divider"},{"type":"callout","icon":"heart","content":"You do not have to do this perfectly. You are learning — and that matters. The goal is not to eliminate emotion. The goal is to understand it, meet it with kindness, and choose a new response. Every time you walk through this process, you weaken an old neural pathway and strengthen a new one."},{"type":"quote","content":"Forgiveness released the burden. This practice teaches your body how to live like it is free. That is how freedom becomes practical: one steady, honest choice at a time.","attribution":"Trisha Jamison"},{"type":"divider"},{"type":"heading","content":"A Note From Trisha"},{"type":"text","content":"Now that you have reached the end of this module, pause for a moment and recognize what you just did. You did not simply learn information. You integrated awareness, forgiveness, and intentional change into one powerful practice."},{"type":"text","content":"In 7:1, you saw your patterns clearly. In 7:2, you released what was heavy. In 7:3, you learned how to update what your body learned when it was trying to survive. Most people never get this framework."},{"type":"text","content":"Old reactions may resurface at times. That does not erase your progress. It simply means you are human. Return to what you have learned. Slow down. Practice again. Strengthen the new pathway."},{"type":"quote","content":"You are no longer operating on autopilot. You are living with awareness, and that changes everything. Forgiveness sets your heart free. Now you are teaching your nervous system how to live in that freedom.","attribution":"Trisha Jamison"}]}'
WHERE module_id = (SELECT id FROM modules WHERE module_number = '7') AND sort_order = 3;

-- Verify
SELECT m.title as module, m.is_preview as module_preview,
       l.title as lesson, l.sort_order, l.is_preview as lesson_preview,
       length(l.content_json::text) as content_length
FROM modules m
JOIN lessons l ON l.module_id = m.id
WHERE m.module_number = '7'
ORDER BY l.sort_order;
